import{_ as a,c as i,o as d,a as e,b as o}from"./app.426dd711.js";const f=JSON.parse('{"title":"8. Propiedad Colectiva (Collective Ownership)","description":"","frontmatter":{},"headers":[],"relativePath":"practices/collective-ownership.md"}'),r={name:"practices/collective-ownership.md"},c=e("h1",{id:"_8-propiedad-colectiva-collective-ownership",tabindex:"-1"},[o("8. Propiedad Colectiva "),e("em",null,"(Collective Ownership)"),o(),e("a",{class:"header-anchor",href:"#_8-propiedad-colectiva-collective-ownership","aria-hidden":"true"},"#")],-1),l=e("p",null,"La propiedad colectiva del c\xF3digo tiene por objetivo que todos los miembros del equipo conozcan \u201Cqu\xE9\u201D y \u201Cc\xF3mo\u201D se est\xE1 desarrollando el sistema, evitando as\xED, lo que sucede en muchas empresas, que existen \u201Cprogramadores due\xF1os de un c\xF3digo\u201D y cuando surge un problema, nadie m\xE1s que \xE9l puede resolverlo, puesto que el resto del equipo, desconoce c\xF3mo fue hecho y cu\xE1les han sido sus requerimientos a lo largo del desarrollo.",-1),n=e("p",null,"No debe existir un programador \u201Cdue\xF1o\u201D de un determinado c\xF3digo o funcionalidad. Cualquiera puede modificar cualquier m\xF3dulo en cualquier momento y nadie tiene la propiedad de ning\xFAn m\xF3dulo. El c\xF3digo que el equipo genere para llevar a cabo un proyecto es propiedad de cada uno de los miembros del equipo. De esta forma cualquier miembro del equipo podr\xE1 modificar un m\xF3dulo o porci\xF3n de c\xF3digo generado por otro miembro si lo cree conveniente.",-1),s=e("blockquote",null,[e("p",null,"Dentro de un equipo no existen derechos de autor ni prohibiciones de ning\xFAn tipo a la hora de modificar el c\xF3digo de un compa\xF1ero. Todo el c\xF3digo desarrollado por cada miembro del equipo es cedido para el bien del propio equipo y poni\xE9ndolo a su disposici\xF3n para cualquier mejora o comentario.")],-1),t=e("p",null,"La propiedad colectiva del c\xF3digo permite al grupo trabajar mas r\xE1pidamente y rendir de una forma mas eficaz debido a que no se producen los retardos o esperas ocasionados por la propiedad privada de un c\xF3digo y la incapacidad de modificarlo sin pedir permiso al miembro del equipo \u201Ccreador\u201D del c\xF3digo.",-1),p=[c,l,n,s,t];function u(m,h,_,q,v,g){return d(),i("div",null,p)}const x=a(r,[["render",u]]);export{f as __pageData,x as default};
